      /* <flatten type="Javascript"> */
function load$Grid(g) {
  g.add_onResponseComplete(on$GridPhysicalCountQtyUpdate$ResponseComplete);
  g.add_commandEvent(on$GridPhysicalCountQtyUpdate$ExecuteCommand);
}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$GridPhysicalCountQtyUpdate$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridPhysicalCountQtyUpdate$ResponseComplete);} catch (ex) {}
}
function on$GridPhysicalCountQtyUpdate$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, k;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'PhysicalCountQtyUpdateImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    case 'DeleteData':
      id = g.get_id(), k = (g._language == 'v' ? 'Hệ thống sẽ <span class="TaskDialogContentHighlight">xóa tất cả bản ghi</span>, bạn có chắc chắn xóa không?' : 'Are you sure you want to <span class="TaskDialogContentHighlight">delete all record</span>?');
      $message.show(k, 0, String.format("request$DeleteData$Grid($find('{0}'));", id), String.format("$find('{0}')._focusWhenTabChanged();", id));
      break;
    default:
      break;
  }
}
function on$GridPhysicalCountQtyUpdate$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    case 'DeleteData':
      if (result[0].Value == 1) g.goToPage(-1);
        else $message.show($df.getResources(g._language, "Message.NotAccess"));
      break;
    default:
      break;
  }
}
function request$DeleteData$Grid(g) {(g._denyDelete || !g._authorizeDelete) ? $message.show(((g._denyDelete) ? g._denyMessage : $df.getResources(g._language, "Message.NotAccess"))) : g.request(g, 'DeleteData', 'DeleteData', [['stt_rec', 'String', g._voucherID]]);}
function show$Form(g, c) {(g._authorize == 1) ? ((g._denyNew) ? $message.show(g._denyMessage) : g.showForm(c)) : $message.show($df.getResources(g._language, "Message.NotAccess"));}
/* </flatten> */
      &DowloadScript;
